#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define dd double
const int N=5005;
int n,vis[N],id;
dd x[N],y[N],dis[N],ans,mn; //dis i 是记录 i 和走过的点 （标记为 1 的）之间的最小距离 
/*
过程 ： 
	1)将起点（那个点都行） 标记为 1 
	2)找一条最短的边 连接 之前走过的点（标记为 1 的） 和没走过的点（标记为 0 的） 
	3)使用这条边（ ans+=边长 ） 并将那个没走过的点（标记为 0 的）点标记为 1 
	4)更新这个刚刚  标记为 1 的点 所连接的 没走过的点（标记为 0 的） 的 dis 
*/ 
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>x[i]>>y[i];
		dis[i]=1e13;
	}
	dis[1]=0;
	vis[1]=1;
	for(int i=1;i<=n;i++)
	{
		mn=1e9;
		for(int j=1;j<=n;j++)
		{
			if((!vis[j])&&(dis[j]<mn))
			{
				mn=dis[j];
				id=j; 
			}
		}
		vis[id]=1;
		ans+=dis[id];
		for(int j=1;j<=n;j++)
		{
			dis[j]=min(dis[j],sqrt((x[id]-x[j])*(x[id]-x[j])+(y[id]-y[j])*(y[id]-y[j])));
		}
	}
	cout<<fixed<<setprecision(2)<<ans;
	return 0;
}
